// T608 TenantLifecycleManager — suspend-not-delete + delegated purge

async suspend(reason: string): Promise<DataProcessResult<void>> {
  const tenantId = this.tenantContext.getTenantId(); // ALS only

  // updateDocument ONLY — deleteDocument is prohibited
  await this.registry.updateDocument('xiigen-tenants', tenantId, {
    status: 'SUSPENDED',
    suspendedAt: new Date().toISOString(),
    suspensionReason: reason,
  }); // F1519

  await this.auditService.record(tenantId, 'SUSPENDED'); // F1525

  // cascadeToSubscriptions:true ALWAYS — subscription service listens to this event
  await this.queue.enqueue('TenantSuspended', {
    tenantId,
    cascadeToSubscriptions: true, // REQUIRED — never false, never omitted
    suspendedAt: new Date().toISOString(),
    suspensionReason: reason,
    suspendedBy: 'SYSTEM',
  });
  return DataProcessResult.success();
}

async terminate(): Promise<DataProcessResult<void>> {
  const tenantId = this.tenantContext.getTenantId(); // ALS only

  // One-way hash — raw tenantId NEVER in events
  const tombstoneRef = crypto.createHash('sha256').update(tenantId).digest('hex');

  // Read retention from FREEDOM — no hardcoded period
  const retentionDays = await this.freedom.getConfig('tenant_data_retention_days');

  await this.registry.updateDocument('xiigen-tenants', tenantId, {
    status: 'TERMINATED',
    terminatedAt: new Date().toISOString(),
    tombstoneRef,
  }); // F1519

  await this.auditService.record(tenantId, 'TERMINATED'); // F1525

  // Delegated purge — T608 never deletes data directly
  const purgeRef = crypto.randomUUID();
  await this.queue.enqueue('DataPurgeRequested', { tombstoneRef, retentionDays, purgeRef });
  await this.queue.enqueue('TenantTerminated', { tombstoneRef, terminatedAt: new Date().toISOString(), dataPurgeRequestedRef: purgeRef });
  return DataProcessResult.success();
}
